<template>
	<view class="components-form">
		<view :style="{paddingTop: vuex_custom_bar_height + 'px'}">

			<dynamic-demo-template ref="demoTemplate" :tips="tips" :sectionList="sectionList" :full="false"
				@click="click">
				<tn-form :model="form" ref="uForm" :errorType="['message']">
					<view class="order-details">

						<view class="order-info">
							<view class="order-number">订单号：{{ orderNumber }}</view>
							<view class="order-text">报修内容：{{ orderText }}</view>
						</view>
						<view class="repairman-info">
							<view class="repairman-name">维修人员：{{ repairmanName }}</view>
							<view class="repairman-phone">联系电话：{{ repairmanPhone }}</view>
						</view>
						<view class="progress-info">
							<view class="progress-title">维修进度：</view>
							<view class="progress-item" v-for="(item, index) in progress" :key="index">
								<view class="progress-status">{{ item.status }}</view>
								<view class="progress-time">{{ item.time }}</view>

							</view>
						</view>
						<view class="button-group">
							<tn-button class="button" type="primary" size="mini" @click="handleCancelOrder">取消订单
							</tn-button>
							<tn-button class="button" type="primary" size="mini" @click="handleFinishOrder">完成订单
							</tn-button>
						</view>

					</view>


				</tn-form>


			</dynamic-demo-template>
		</view>
	</view>

</template>
<script>
	import dynamicDemoTemplate from '@/libs/components/dynamic-demo-template.vue'

	export default {
		components: {
			dynamicDemoTemplate
		},
		data() {
			return {
				orderNumber: '1',
				orderText: '厕所灯故障，无法照明',
				repairmanName: '兰利',
				repairmanPhone: '1234567899',
				progress: [{
						time: '2023-02-12  10:00',
						status: '已接单'
					},
					{
						time: '2023-02-12  12:00',
						status: '正在维修'
					}
				]
			}
		},
		methods: {
			handleCancelOrder() {
				this.orderStatus = '已取消'
			},
			handleFinishOrder() {
				this.orderStatus = '已完成'
			}
		}
	}
</script>

<style lang="scss" scoped>
	.agreement {
		display: flex;
		align-items: center;
		margin: 40rpx 0;

		&-text {
			padding-left: 8rpx;
			color: $tn-font-sub-color;
		}
	}
</style>
